          # OpenSSL for cargo builds (rust crates like openssl-sys)
          export PKG_CONFIG_PATH="${pkgs.openssl.dev}/lib/pkgconfig''${PKG_CONFIG_PATH:+:$PKG_CONFIG_PATH}"
          export OPENSSL_DIR="${pkgs.openssl.dev}"
